  const estimates=data.estimates.filter(estimate=>estimate.clientId===client.id), payments=data.payments.filter(payment=>invoiceIds.has(payment.invoiceId));
  const invoiced=invoices.reduce((sum,invoice)=>sum+invoice.amount,0), paid=payments.reduce((sum,payment)=>sum+payment.amount,0), due=invoices.reduce((sum,invoice)=>sum+invoice.balance,0), quoted=estimates.reduce((sum,estimate)=>sum+estimate.amount,0);
