  const updateStatus=async status=>{setBusy(true);setError('');try{await apiJson(`/api/invoices/${encodeURIComponent(invoice.id)}/status`,{method:'PATCH',headers:{'content-type':'application/json'},body:JSON.stringify({status})});await reload()}catch(statusError){setError(statusError.message);setBusy(false)}};
